using Microsoft.EntityFrameworkCore;

// Cosmos DB context demonstrating EF Core 9 breaking changes and fixes.
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    public DbSet<DiscountedProduct> DiscountedProducts => Set<DiscountedProduct>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "ShopDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);
            b.HasNoDiscriminator(); // see note below
        });

        // ─── Breaking change #1: Discriminator property renamed ───────────
        // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
        // Existing Cosmos documents still store "Discriminator".
        // Fix: explicitly configure the old property name so EF reads existing docs.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator")
            .HasValue<Product>("Product")
            .HasValue<DiscountedProduct>("DiscountedProduct");
    }

    // ─── Breaking change #2: Synchronous Cosmos queries removed ───────────
    // EF Core 9 removed sync I/O for the Cosmos provider.
    // Calls like .ToList(), .First(), .Count() now throw
    // InvalidOperationException at runtime.
    // Fix: convert all sync LINQ queries to their async equivalents.

    // BEFORE (throws in EF Core 9):
    // var products = db.Products.Where(p => p.Price > 10).ToList();
    // var first    = db.Products.First(p => p.Id == id);

    // AFTER (correct for EF Core 9):
    public async Task<List<Product>> GetExpensiveProductsAsync()
        => await Products.Where(p => p.Price > 10).ToListAsync();

    public async Task<Product> GetProductAsync(string id)
        => await Products.FirstAsync(p => p.Id == id);
}

class Product
{
    public string Id { get; set; } = null!;
    public string Category { get; set; } = null!;
    public decimal Price { get; set; }
}

class DiscountedProduct : Product
{
    public decimal Discount { get; set; }
}

